(function(){"use strict";function b(Y){return Y<2?350:Y<4?500:650}let S=[],D=[];self.onmessage=Y=>{const M=Y.data;if(M){if(M.type==="init"){S=(M.stars||[]).map(t=>({id:t.id,ra:t.ra,dec:t.dec,mag:t.mag,radius:b(t.mag)}));const T=M.constellations||[];D=[],T.forEach(t=>{t.segments&&t.segments.forEach(o=>{D.push({ra1:o.ra1,dec1:o.dec1,ra2:o.ra2,dec2:o.dec2})})})}else if(M.type==="update"){const{lst:_,latitude:T}=M,t=Math.PI/180,o=T*t,l=Math.cos(o),d=Math.sin(o),z=S.length,R=new Float32Array(z*4);for(let a=0;a<z;a++){const n=S[a],E=(_-n.ra*15)*t,L=n.dec*t,f=Math.cos(L),A=Math.sin(L);let e=d*A+l*f*Math.cos(E);e=Math.max(-1,Math.min(1,e));const i=Math.asin(e),g=-Math.sin(E)*f,p=l*A-d*f*Math.cos(E);let h=Math.atan2(g,p);h<0&&(h+=2*Math.PI);const r=n.radius,u=Math.cos(i),x=r*u*Math.sin(h),N=r*Math.sin(i),O=-r*u*Math.cos(h),m=i>=-.034906585?1:0,C=a*4;R[C]=x,R[C+1]=N,R[C+2]=O,R[C+3]=m}const w=D.length,s=new Float32Array(w*6);let c=0;for(let a=0;a<w;a++){const n=D[a],y=(_-n.ra1*15)*t,E=n.dec1*t,L=Math.cos(E),f=Math.sin(E);let A=d*f+l*L*Math.cos(y);A=Math.max(-1,Math.min(1,A));const e=Math.asin(A),i=(_-n.ra2*15)*t,g=n.dec2*t,p=Math.cos(g),h=Math.sin(g);let r=d*h+l*p*Math.cos(i);r=Math.max(-1,Math.min(1,r));const u=Math.asin(r);if(e>=-.0349&&u>=-.0349){const x=Math.cos(e),N=-Math.sin(y)*L,O=l*f-d*L*Math.cos(y);let m=Math.atan2(N,O);m<0&&(m+=2*Math.PI);const C=480*x*Math.sin(m),B=480*Math.sin(e),F=-480*x*Math.cos(m),P=Math.cos(u),G=-Math.sin(i)*p,H=l*h-d*p*Math.cos(i);let I=Math.atan2(G,H);I<0&&(I+=2*Math.PI);const v=480*P*Math.sin(I),V=480*Math.sin(u),j=-480*P*Math.cos(I);s[c++]=C,s[c++]=B,s[c++]=F,s[c++]=v,s[c++]=V,s[c++]=j}}self.postMessage({type:"result",coords:R,constellationCoords:s,validConstellationElements:c},[R.buffer,s.buffer])}}}})();
